
const water = document.getElementById('water');
const rain = document.getElementById('rain');
const risk = document.getElementById('risk');

let waterLevel = 2.4;
let rainLevel = 42;

setInterval(()=>{

waterLevel += (Math.random() - .5) * .3;
rainLevel += (Math.random() - .5) * 5;

water.innerText = waterLevel.toFixed(1) + 'm';
rain.innerText = Math.abs(rainLevel).toFixed(0) + 'mm/h';

if(waterLevel > 3.2){
risk.innerText = 'HIGH';
}else if(waterLevel > 2.7){
risk.innerText = 'MEDIUM';
}else{
risk.innerText = 'LOW';
}

},2000);

const canvas = document.getElementById('chart');
const ctx = canvas.getContext('2d');

function resize(){
canvas.width = canvas.offsetWidth;
canvas.height = 320;
}

resize();

window.addEventListener('resize',resize);

let points = [];

for(let i=0;i<50;i++){
points.push(Math.random() * 250 + 20);
}

function draw(){

ctx.clearRect(0,0,canvas.width,canvas.height);

ctx.beginPath();
ctx.moveTo(0, points[0]);

points.forEach((p,i)=>{
const x = (canvas.width / points.length) * i;
ctx.lineTo(x,p);
});

ctx.strokeStyle = '#00d9ff';
ctx.lineWidth = 3;
ctx.shadowBlur = 20;
ctx.shadowColor = '#00d9ff';
ctx.stroke();

points.shift();
points.push(Math.random() * 250 + 20);

requestAnimationFrame(draw);

}

draw();

